// Pseudo drift check for rollback decision
function evaluateRollback(metrics) {
  const { predictionLatency, errorRate, driftScore, costDelta } = metrics;
  const thresholds = { latencyMs: 100, errorRate: 0.01, driftScore: 0.15 };

  const shouldRollback =
    predictionLatency > thresholds.latencyMs ||
    errorRate > thresholds.errorRate ||
    driftScore > thresholds.driftScore ||
    costDelta > 0.25;

  return { shouldRollback, reason: getReason(metrics, thresholds) };
}
```

