// Pseudo DP transform sketch
function dpClipAndNoise(features, clipBound, epsilon) {
  Object.keys(features).forEach(k => {
    features[k] = Math.max(-clipBound, Math.min(clipBound, features[k]));
  });
  for (let k in features) { features[k] += laplace(1/epsilon); }
  return features;
}
